-- V16: Wörter des Tages bis Jahresende 2026 auffüllen
-- Führt dieses Skript in Supabase im SQL Editor aus.
-- Bestehende Einträge an den jeweiligen Tagen werden aktualisiert, damit jeder Tag gefüllt ist.

on conflict (datum) do update set
  wort = excluded.wort,
  lautschrift = excluded.lautschrift,
  wortart = excluded.wortart,
  definition = excluded.definition,
  beispielsatz = excluded.beispielsatz,
  synonyme = excluded.synonyme;
